-- Current schema — user_email duplicated across many tables.
-- One column to fix here; the lesson generalises to the other 11.

CREATE TABLE users (
  id          BIGSERIAL PRIMARY KEY,
  email       TEXT NOT NULL UNIQUE,
  name        TEXT NOT NULL
);

CREATE TABLE orders (
  id           BIGSERIAL PRIMARY KEY,
  user_id      BIGINT NOT NULL,
  user_email   TEXT NOT NULL,         -- ← duplicated, can go stale
  order_total  NUMERIC(10,2) NOT NULL,
  placed_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- A user changes email; only users.email is updated.
UPDATE users SET email = 'ada.new@example.com' WHERE id = 1;

-- The receipts query — pulls from orders.user_email — sends to the OLD address.
SELECT user_email FROM orders WHERE user_id = 1 LIMIT 1;

