CREATE OR REPLACE FUNCTION sync_user_email() RETURNS trigger AS $$
BEGIN
  UPDATE orders         SET user_email = NEW.email WHERE user_id = NEW.id;
  UPDATE invoices       SET user_email = NEW.email WHERE user_id = NEW.id;
  UPDATE shipments      SET user_email = NEW.email WHERE user_id = NEW.id;
  UPDATE refunds        SET user_email = NEW.email WHERE user_id = NEW.id;
  UPDATE support_tickets SET user_email = NEW.email WHERE user_id = NEW.id;
  -- (and 7 more tables)
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER on_user_email_update
AFTER UPDATE OF email ON users
FOR EACH ROW EXECUTE FUNCTION sync_user_email();
